class Solution {
public:
    string robotWithString(string s) {
        string result;
        string stack;

        for (char c : s) {
            stack.push_back(c);
            while (!stack.empty() && (result.empty() || result.back() > stack.back())) {
                result.push_back(stack.back());
                stack.pop_back();
            }
        }

        while (!stack.empty()) {
            result.push_back(stack.back());
            stack.pop_back();
        }

        return result;
    }
};
```
